script:
// ── CHANGE to your actual app name ───────────────────────────
var TD_METHOD = "fleet.api.api.get_technician_employees";
// ─────────────────────────────────────────────────────────────

var TD_COLORS = [
  "#2490ef","#7b5ea7","#e67e22","#27ae60",
  "#e74c3c","#16a085","#d35400","#2980b9",
  "#8e44ad","#c0392b","#1abc9c","#f39c12",
  "#2ecc71","#3498db","#9b59b6","#e91e63"
];

var td_page  = 0;
var td_all   = [];
var td_scope = null;

// ── Wait for frappe + DOM ─────────────────────────────────────
(function td_wait() {
  if (typeof frappe === "undefined" || !frappe.call) {
    setTimeout(td_wait, 200); return;
  }
  var found = document.getElementById("td-root");
  if (found) {
    td_scope = document;
  } else {
    var all = document.querySelectorAll("*");
    for (var i = 0; i < all.length; i++) {
      if (all[i].shadowRoot) {
        var el = all[i].shadowRoot.getElementById("td-root");
        if (el) { td_scope = all[i].shadowRoot; break; }
      }
    }
  }
  if (!td_scope || !td_scope.getElementById("td-grid")) {
    setTimeout(td_wait, 200); return;
  }
  td_init();
})();

function td$(id) { return td_scope.getElementById(id); }

// ── Fix Frappe image path → always a full usable URL ─────────
function td_img_url(path) {
  if (!path || !path.trim()) return "";
  var p = path.trim();
  // Already a full URL
  if (p.indexOf("http://") === 0 || p.indexOf("https://") === 0) return p;
  // Relative path starting with /files/ or /private/ — prepend origin
  if (p.indexOf("/") === 0) return window.location.origin + p;
  // Anything else — try prepending origin
  return window.location.origin + "/" + p;
}

// ── Main init ────────────────────────────────────────────────
function td_init() {
  td_loading();

  frappe.call({
    method: TD_METHOD,
    callback: function(r) {
      if (!r || !r.message || !r.message.length) {
        td_empty("No employees found with the 'Technician' role.");
        return;
      }
      td_all = r.message;
      td_enrich(td_all, function() {
        td_setcount(td_all.length);
        td_render();
      });
    },
    error: function(e) {
      console.error("Technician API error:", e);
      td_empty("Error loading data. Check console.");
    }
  });
}

// ── Enrich: task count only from JS (unread_count comes from Python API) ─
function td_enrich(list, done) {
  var pending = list.length;
  if (!pending) { done(); return; }

  function tick() { if (--pending === 0) done(); }

  list.forEach(function(emp) {
    emp.task_count = 0;
    // emp.unread_count is already populated by the Python API

    if (emp.user_id) {
      frappe.call({
        method: "frappe.client.get_count",
        args: {
          doctype: "ToDo",
          filters: [
            ["allocated_to", "=", emp.user_id],
            ["status", "in", ["Open", "Overdue"]]
          ]
        },
        callback: function(r) { emp.task_count = (r && r.message) ? r.message : 0; tick(); },
        error: function() { tick(); }
      });
    } else {
      tick();
    }
  });
}

// ── Render page ───────────────────────────────────────────────
function td_render() {
  var g = td$("td-grid"); if (!g) return;

  var total = td_all.length;
  var pages = Math.ceil(total / 16) || 1;
  if (td_page >= pages) td_page = pages - 1;
  if (td_page < 0)      td_page = 0;

  var start = td_page * 16;
  var slice = td_all.slice(start, start + 16);

  td_setcount(total);
  g.innerHTML = "";

  if (!slice.length) {
    g.innerHTML = '<div class="td-empty">No technicians to display.</div>';
    td_paginate(total, pages);
    return;
  }

  slice.forEach(function(emp, i) {
    var color  = TD_COLORS[(start + i) % TD_COLORS.length];
    var name   = emp.employee_name || emp.name || "Unknown";
    var mobile = emp.cell_number   || emp.mobile_no || "—";
    var dept   = emp.department    || "—";
    var email  = emp.company_email || "";
    var tasks  = emp.task_count    || 0;
    var unread = emp.unread_count  || 0;
    var imgUrl = td_img_url(emp.image || "");
    var ini    = td_ini(name);
    var delay  = (i * 0.04).toFixed(2) + "s";

    var card = document.createElement("div");
    card.className = "td-card";
    card.style.animationDelay = delay;
    // (function(en){ card.onclick = function(){ frappe.set_route("Form","Employee",en); }; })(emp.name);

    // Unread badge on card corner
    if (unread > 0) {
      var badge = document.createElement("div");
      badge.className = "td-msg-badge";
      badge.textContent = unread > 99 ? "99+" : unread;
      badge.title = unread + " unread message" + (unread !== 1 ? "s" : "");
      card.appendChild(badge);
    }

    // ── Avatar ───────────────────────────────────────────────
    var avWrap = document.createElement("div");
    avWrap.className = "td-av-wrap";

    var av = document.createElement("div");
    av.className = "td-av";

    if (imgUrl) {
      // Try loading the image; fall back to initials on error
      var im = new Image();
      im.alt     = name;
      im.loading = "lazy";
      im.style.cssText = "width:100%;height:100%;object-fit:cover;border-radius:50%;display:block;";

      im.onload = function() {
        av.style.background = "";
        av.innerHTML = "";
        av.appendChild(im);
      };
      im.onerror = function() {
        av.style.background = td_gradient(color);
        av.textContent = ini;
      };

      // Set background + initials first while image loads
      av.style.background = td_gradient(color);
      av.textContent = ini;
      im.src = imgUrl;  // trigger load AFTER handlers are set
    } else {
      av.style.background = td_gradient(color);
      av.textContent = ini;
    }

    avWrap.appendChild(av);
    card.appendChild(avWrap);

    // ── Name ─────────────────────────────────────────────────
    var nm = document.createElement("div");
    nm.className = "td-name";
    nm.textContent = name;
    card.appendChild(nm);

    // ── Mobile number (instead of role) ──────────────────────
    var mb = document.createElement("div");
    mb.className = "td-mobile";
    if (mobile && mobile !== "—") {
      mb.innerHTML =
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" '
        + 'style="width:11px;height:11px;vertical-align:middle;margin-right:3px;">'
        + '<rect x="5" y="2" width="14" height="20" rx="2"/>'
        + '<line x1="12" y1="18" x2="12.01" y2="18"/>'
        + '</svg>' + mobile;
    } else {
      mb.textContent = "No mobile";
    }
    card.appendChild(mb);

    // ── Dept ─────────────────────────────────────────────────
    var dp = document.createElement("div");
    dp.className = "td-dept";
    dp.textContent = dept;
    card.appendChild(dp);

    // ── Divider ──────────────────────────────────────────────
    var ln = document.createElement("div"); ln.className = "td-line";
    card.appendChild(ln);

    // ── Footer ───────────────────────────────────────────────
    var ft = document.createElement("div"); ft.className = "td-foot";

    // Task chip — clicking opens task list filtered by this user
    var tc = document.createElement("button");
    tc.className = "td-stat";
    tc.title = tasks + " open task" + (tasks !== 1 ? "s" : "");
    tc.innerHTML =
      '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">'
      + '<path d="M9 11l3 3L22 4"/>'
      + '<path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/>'
      + '</svg><span>' + tasks + '</span>';
    (function(uid) {
      tc.onclick = function(e) {
        e.stopPropagation();
        var filter = JSON.stringify(["like", "%" + uid + "%"]);
        window.open("/app/task?_assign=" + encodeURIComponent(filter), "_blank");
      };
    })(emp.user_id || "");
    ft.appendChild(tc);

    // Message chip
    var mc = document.createElement("div");
    mc.className = "td-stat" + (unread > 0 ? " td-msg-stat" : "");
    mc.title = unread + " unread message" + (unread !== 1 ? "s" : "");
    mc.innerHTML =
      '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">'
      + '<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>'
      + '</svg><span>' + unread + '</span>';
    ft.appendChild(mc);

    // Profile button
    var pb = document.createElement("button");
    pb.className = "td-btn"; pb.title = "Open Employee";
    pb.innerHTML =
      '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">'
      + '<path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>'
      + '<circle cx="12" cy="7" r="4"/></svg>';
    (function(en){ pb.onclick = function(e){ e.stopPropagation(); frappe.set_route("Form","Employee",en); }; })(emp.name);
    ft.appendChild(pb);

    card.appendChild(ft);
    g.appendChild(card);
  });

  td_paginate(total, pages);
}

// ── Pagination ────────────────────────────────────────────────
function td_paginate(total, pages) {
  var wrap = td$("td-pages"); if (!wrap) return;
  wrap.innerHTML = "";
  if (pages <= 1) return;

  var prev = document.createElement("button");
  prev.className = "td-pbtn"; prev.textContent = "← Prev";
  prev.disabled = td_page === 0;
  prev.onclick = function() { if(td_page>0){td_page--;td_render();} };

  var info = document.createElement("span");
  info.className = "td-pinfo";
  info.textContent = "Page "+(td_page+1)+" of "+pages+" · "+total+" technicians";

  var next = document.createElement("button");
  next.className = "td-pbtn"; next.textContent = "Next →";
  next.disabled = td_page >= pages-1;
  next.onclick = function() { if(td_page<pages-1){td_page++;td_render();} };

  wrap.appendChild(prev); wrap.appendChild(info); wrap.appendChild(next);
}

// ── Helpers ───────────────────────────────────────────────────
function td_setcount(n) {
  var el = td$("td-count");
  if (el) el.textContent = (n||0)+" Technician"+(n!==1?"s":"");
}
function td_loading() {
  var g = td$("td-grid"); if(!g) return;
  g.innerHTML =
    '<div id="td-loader"><div id="td-spinner"></div><span>Loading technicians…</span></div>';
}
function td_empty(msg) {
  var pg = td$("td-pages"); if(pg) pg.innerHTML = "";
  var g  = td$("td-grid");  if(g)  g.innerHTML = '<div class="td-empty">'+msg+'</div>';
  td_setcount(0);
}
function td_ini(name) {
  var p = (name||"").trim().split(" ").filter(Boolean);
  if (!p.length) return "?";
  if (p.length === 1) return p[0][0].toUpperCase();
  return (p[0][0]+p[p.length-1][0]).toUpperCase();
}
function td_gradient(c) {
  return "linear-gradient(135deg,"+c+"dd,"+c+"88)";
}

style:
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

#td-root {
  font-family: 'Inter', -apple-system, sans-serif;
  background: #f4f5f7;
  color: #1c1c1c;
  padding: 24px;
  border-radius: 8px;
}

/* Header */
#td-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 20px;
}
#td-title-wrap {
  display: flex;
  align-items: center;
  gap: 10px;
}
#td-title {
  font-size: 18px;
  font-weight: 600;
  margin: 0;
  color: #1c1c1c;
}
#td-title span { color: #2490ef; }
#td-count {
  font-size: 11px;
  font-weight: 500;
  padding: 3px 10px;
  border-radius: 100px;
  background: #e8f3fd;
  color: #2490ef;
  border: 1px solid #c5dff8;
}

/* Grid */
#td-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
}

/* Loader */
#td-loader {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  padding: 60px 0;
  color: #8d99a6;
  font-size: 13px;
}
#td-spinner {
  width: 26px; height: 26px;
  border: 2px solid #e2e6ea;
  border-top-color: #2490ef;
  border-radius: 50%;
  animation: tdspin 0.7s linear infinite;
}
@keyframes tdspin { to { transform: rotate(360deg); } }

/* Empty */
.td-empty {
  grid-column: 1 / -1;
  text-align: center;
  padding: 60px 0;
  color: #8d99a6;
  font-size: 13px;
}

/* Card */
.td-card {
  background: #ffffff;
  border: 1px solid #e2e6ea;
  border-radius: 10px;
  padding: 18px 14px 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  position: relative;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s, border-color 0.2s;
  animation: tdup 0.35s ease both;
  overflow: visible;
}
.td-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 6px 24px rgba(0,0,0,0.10);
  border-color: #2490ef;
}
@keyframes tdup {
  from { opacity: 0; transform: translateY(10px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* Unread message badge on card top-right */
.td-msg-badge {
  position: absolute;
  top: -6px;
  right: -6px;
  background: #e74c3c;
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  min-width: 18px;
  height: 18px;
  border-radius: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 4px;
  border: 2px solid #f4f5f7;
  z-index: 10;
  animation: tdbounce 0.4s ease;
}
@keyframes tdbounce {
  0%   { transform: scale(0); }
  70%  { transform: scale(1.2); }
  100% { transform: scale(1); }
}

/* Avatar wrap — for stacking notification dot */
.td-av-wrap {
  position: relative;
  width: 60px; height: 60px;
  flex-shrink: 0;
}

/* Avatar */
.td-av {
  width: 60px; height: 60px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  font-weight: 700;
  color: #fff;
  overflow: hidden;
  border: 2px solid #e2e6ea;
}
.td-av img {
  width: 100%; height: 100%;
  object-fit: cover;
  border-radius: 50%;
}

/* Text */
.td-name {
  font-size: 13px; font-weight: 600;
  text-align: center; width: 100%;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
  color: #1c1c1c;
  margin-top: 2px;
}
.td-role {
  font-size: 11px; color: #2490ef; font-weight: 500;
  text-align: center; width: 100%;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.td-mobile {
  font-size: 11.5px; color: #525f7f; font-weight: 500;
  text-align: center; width: 100%;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.td-dept {
  font-size: 11px; color: #8d99a6;
  text-align: center; width: 100%;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}

/* Divider */
.td-line {
  width: 100%; height: 1px;
  background: #f0f1f3;
  margin: 6px 0 2px;
}

/* Footer stats row */
.td-foot {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 6px;
}

/* Task stat chip */
.td-stat {
  display: flex;
  align-items: center;
  gap: 5px;
  background: #f4f5f7;
  border: 1px solid #e2e6ea;
  border-radius: 8px;
  padding: 4px 8px;
  font-size: 11px;
  font-weight: 500;
  color: #525f7f;
  flex: 1;
  justify-content: center;
  cursor: default;
  font-family: inherit;
}
button.td-stat {
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, color 0.15s;
}
button.td-stat:hover {
  background: #e8f3fd;
  border-color: #2490ef;
  color: #2490ef;
}
.td-stat svg { width: 13px; height: 13px; flex-shrink: 0; }
.td-stat.td-msg-stat {
  color: #e74c3c;
  background: #fdf0ef;
  border-color: #f5c6c2;
}
.td-stat.td-msg-stat svg { color: #e74c3c; }

/* Action button */
.td-btn {
  width: 26px; height: 26px;
  border-radius: 6px;
  background: #f4f5f7;
  border: 1px solid #e2e6ea;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; color: #8d99a6;
  transition: all 0.15s; padding: 0;
}
.td-btn:hover {
  background: #e8f3fd;
  border-color: #2490ef;
  color: #2490ef;
}
.td-btn svg { width: 13px; height: 13px; }

/* Pagination */
#td-pages {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  margin-top: 20px;
  padding-top: 16px;
  border-top: 1px solid #e2e6ea;
}
#td-pages:empty { display: none; }
.td-pbtn {
  padding: 6px 16px;
  border-radius: 6px;
  background: #fff;
  border: 1px solid #e2e6ea;
  color: #1c1c1c;
  font-family: 'Inter', sans-serif;
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
}
.td-pbtn:hover:not(:disabled) {
  background: #e8f3fd;
  border-color: #2490ef;
  color: #2490ef;
}
.td-pbtn:disabled { opacity: 0.4; cursor: not-allowed; }
.td-pinfo { font-size: 11px; color: #8d99a6; }

/* Responsive */
@media (max-width: 1100px) { #td-grid { grid-template-columns: repeat(3,1fr); } }
@media (max-width: 780px)  { #td-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width: 480px)  { #td-grid { grid-template-columns: 1fr; } }
